// PrintOpAggregate: 연산별 집계 출력
func PrintOpAggregate(aggMap map[string]*OpAggregate) {
	fmt.Println("\n=== 벡터 연산별 성능 집계 ===")
	fmt.Printf("%-20s %10s %10s %10s %10s %10s %8s\n",
		"연산", "총호출", "에러율%", "평균ns", "P50ns", "P99ns", "처리량")
	fmt.Println(strings.Repeat("-", 80))

	opOrder := []string{
		OpDotProduct.String(),
		OpCosineSimilarity.String(),
		OpL2Distance.String(),
		OpManhattan.String(),
	}

	for _, opName := range opOrder {
		agg, ok := aggMap[opName]
		if !ok {
			continue
		}
		throughput := 0.0
		if agg.AvgTimeNs > 0 {
			throughput = 1e9 / agg.AvgTimeNs
		}
		fmt.Printf("%-20s %10d %10.2f %10.0f %10d %10d %8.0f\n",
			opName,
			agg.TotalCalls,
			agg.ErrorRate,
			agg.AvgTimeNs,
			agg.P50Ns,
			agg.P99Ns,
			throughput,
		)
	}
}

// PrintDimensionStats: 차원별 성능 출력
func PrintDimensionStats(dimStats []DimensionStats) {
	fmt.Println("\n=== 차원별 성능 분석 ===")
	fmt.Printf("%-12s %12s %12s %15s\n", "차원", "평균시간(ns)", "총호출", "처리량(ops/s)")
	fmt.Println(strings.Repeat("-", 55))
	for _, ds := range dimStats {
		fmt.Printf("%-12d %12.0f %12d %15.0f\n",
			ds.Dimension, ds.AvgTimeNs, ds.TotalCalls, ds.Throughput)
	}
}

// PrintIndexingComparison: 인덱스 비교 결과 출력
func PrintIndexingComparison(stats IndexingStats) {
	fmt.Println("\n=== FlatIndex vs LSHIndex 비교 ===")
	fmt.Printf("문서 수: %d\n", stats.DocCount)
	fmt.Printf("%-20s %15s %15s\n", "지표", "FlatIndex", "LSHIndex")
	fmt.Println(strings.Repeat("-", 52))
	fmt.Printf("%-20s %15.0f %15.0f\n", "삽입 시간(ns/doc)",
		stats.FlatInsertNs, stats.LSHInsertNs)
	fmt.Printf("%-20s %15.0f %15.0f\n", "검색 시간(ns)",
		stats.FlatSearchNs, stats.LSHSearchNs)
	fmt.Printf("%-20s %15s %14.1f%%\n", "LSH 정확도", "100%", stats.LSHAccuracy)
	fmt.Printf("%-20s %15.0f %15.0f\n", "메모리 사용(KB)",
		float64(stats.FlatMemoryKB), float64(stats.LSHMemoryKB))
	fmt.Printf("%-20s %15s %14.2fx\n", "검색 속도비", "1.00x", stats.LSHSpeedupRatio)
}

// ExportCSV: CSV 파일로 통계 내보내기
func ExportCSV(stats []VectorOpStat, filename string) error {
	f, err := os.Create(filename)
	if err != nil {
		return fmt.Errorf("CSV 생성 실패: %w", err)
	}
	defer f.Close()

	w := csv.NewWriter(f)
	defer w.Flush()

	// 헤더
	if err := w.Write([]string{
		"timestamp", "op_type", "dimension", "time_ns", "count", "error_count",
	}); err != nil {
		return err
	}

	// 데이터
	for _, s := range stats {
		if err := w.Write([]string{
			s.Timestamp.Format(time.RFC3339Nano),
			s.OpType,
			strconv.Itoa(int(s.Dimension)),
			strconv.FormatUint(s.TimeNs, 10),
			strconv.FormatUint(s.Count, 10),
			strconv.FormatUint(s.ErrorCount, 10),
		}); err != nil {
			return err
		}
	}

	fmt.Printf("[CSV] %s 저장 완료 (%d 레코드)\n", filename, len(stats))
	return nil
}

// ExportJSON: JSON 파일로 집계 통계 내보내기
func ExportJSON(aggMap map[string]*OpAggregate, dimStats []DimensionStats,
	indexStats IndexingStats, filename string) error {
	report := map[string]interface{}{
		"generated_at":       time.Now().Format(time.RFC3339),
		"platform":           runtime.GOOS + "/" + runtime.GOARCH,
		"op_aggregates":      aggMap,
		"dimension_stats":    dimStats,
		"indexing_comparison": indexStats,
	}

	data, err := json.MarshalIndent(report, "", "  ")
	if err != nil {
		return fmt.Errorf("JSON 변환 실패: %w", err)
	}

	if err := os.WriteFile(filename, data, 0644); err != nil {
		return fmt.Errorf("JSON 저장 실패: %w", err)
	}

	fmt.Printf("[JSON] %s 저장 완료\n", filename)
	return nil
}

