func main() {
	// 플래그 파싱
	durationFlag := flag.Duration("duration", 10*time.Second, "추적 기간 (예: 10s, 1m)")
	dimsFlag := flag.String("dims", "128,256,512", "추적할 차원 (쉼표 구분)")
	csvOut := flag.String("csv", "vector_ops_profile.csv", "CSV 출력 파일")
	jsonOut := flag.String("json", "performance_report.json", "JSON 출력 파일")
	verbose := flag.Bool("v", false, "상세 출력")
	compareIdx := flag.Bool("compare", true, "FlatIndex vs LSH 비교 실행")
	docCount := flag.Int("docs", 1000, "인덱스 비교용 문서 수")
	flag.Parse()

	// 차원 파싱
	dimStrs := strings.Split(*dimsFlag, ",")
	dims := make([]int, 0, len(dimStrs))
	for _, ds := range dimStrs {
		d, err := strconv.Atoi(strings.TrimSpace(ds))
		if err == nil && d > 0 {
			dims = append(dims, d)
		}
	}
	if len(dims) == 0 {
		dims = []int{128, 256, 512}
	}

	fmt.Println("============================================================")
	fmt.Println("  FreeLang 벡터 DB 성능 추적기 (eBPF 시뮬레이션)")
	fmt.Println("============================================================")
	fmt.Printf("  플랫폼: %s/%s\n", runtime.GOOS, runtime.GOARCH)
	fmt.Printf("  추적 기간: %v\n", *durationFlag)
	fmt.Printf("  대상 차원: %v\n", dims)
	fmt.Println()
	fmt.Println("  [참고] eBPF 소스가 내장되어 있습니다.")
	fmt.Println("  실제 BCC 환경: bcc.Compile(ebpfSource)로 커널 레벨 추적 가능")
	fmt.Println("  현재: Go 레벨 시뮬레이션으로 동일 메트릭 수집")
	fmt.Println()

	cfg := TracerConfig{
		Duration:   *durationFlag,
		Dimensions: dims,
		OutputCSV:  *csvOut,
		OutputJSON: *jsonOut,
		Verbose:    *verbose,
	}

	tracer := NewVectorOpTracer(cfg)

	// 1. 벡터 연산 추적
	stats, err := tracer.TraceVectorOps(*durationFlag)
	if err != nil {
		fmt.Fprintf(os.Stderr, "추적 실패: %v\n", err)
		os.Exit(1)
	}

	// 2. 집계 분석
	aggMap := aggregateByOpType(stats)
	dimStats := analyzeDimensions(stats)

	// 3. 출력
	PrintOpAggregate(aggMap)
	PrintDimensionStats(dimStats)

	// 4. dotProduct 퍼센타일 출력
	p50 := DotProductPercentile(stats, 50)
	p99 := DotProductPercentile(stats, 99)
	fmt.Printf("\n[dotProduct 퍼센타일] P50: %.0fns, P99: %.0fns\n", p50, p99)

	// 5. FlatIndex vs LSH 비교 (선택적)
	var indexStats IndexingStats
	if *compareIdx {
		fmt.Printf("\n[인덱스 비교 시작] 문서 수: %d\n", *docCount)
		for _, dim := range dims {
			fmt.Printf("  차원 %d 비교 중...\n", dim)
			is := CompareIndexing(*docCount, dim)
			if dim == dims[0] {
				indexStats = is
			}
			fmt.Printf("  차원 %d: Flat검색=%.0fns, LSH검색=%.0fns, 정확도=%.1f%%, 속도향상=%.2fx\n",
				dim, is.FlatSearchNs, is.LSHSearchNs, is.LSHAccuracy, is.LSHSpeedupRatio)
		}
		PrintIndexingComparison(indexStats)
	}

	// 6. CSV 내보내기
	if err := ExportCSV(stats, *csvOut); err != nil {
		fmt.Fprintf(os.Stderr, "CSV 저장 실패: %v\n", err)
	}

	// 7. JSON 내보내기
	if err := ExportJSON(aggMap, dimStats, indexStats, *jsonOut); err != nil {
		fmt.Fprintf(os.Stderr, "JSON 저장 실패: %v\n", err)
	}

	fmt.Println("\n============================================================")
	fmt.Println("  추적 완료!")
	fmt.Printf("  - CSV: %s\n", *csvOut)
	fmt.Printf("  - JSON: %s\n", *jsonOut)
	fmt.Println("============================================================")
}

// ============================================================================
// search_profiler.go - FreeLang 벡터 DB 검색 성능 프로파일러
// ============================================================================
// 목표: Top-K 검색 성능, 메타데이터 필터 영향, FlatIndex vs LSH 비교,
//       확장성 분석을 통해 최적화 지점 식별
//
// FreeLang 원본 파일 대응:
//   - search.fl: searchCollection, hybridSearch, vectorSearch
//   - index.fl:  flatIndexSearch, lshIndexSearch
//   - collection.fl: insertDocument, filterDocumentsByMetadata
//
// 빌드: go build -o search_profiler search_profiler.go
// 실행: ./search_profiler -docs 1000 -k 10 -dim 128
// ============================================================================

package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"math"
	"math/rand"
	"os"
	"runtime"
	"sort"
