// ============================================================================
// 내장 벡터 DB 시뮬레이터 (FreeLang 로직 재현)
// ============================================================================

// DocMetadata: 문서 메타데이터 (collection.fl VectorDocument.metadata 대응)
type DocMetadata struct {
	Category string
	Lang     string
	Tag      string
	Score    int
}

// Document: VectorDocument 대응
type Document struct {
	ID       string
	Values   []float64
	Metadata DocMetadata
}

// VectorDB: 검색 프로파일러용 벡터 DB
type VectorDB struct {
	docs       []Document
	lshBuckets map[string][]int // bucket key -> doc indices
	lshHPs     [][]float64      // 하이퍼플레인 벡터들
	dim        int
	numHashFns int
}

// NewVectorDB: 벡터 DB 초기화
func NewVectorDB(dim, numHashFns int, seed int64) *VectorDB {
	rng := rand.New(rand.NewSource(seed))
	hps := make([][]float64, numHashFns)
	for i := range hps {
		hp := make([]float64, dim)
		for j := range hp {
			hp[j] = rng.NormFloat64()
		}
		hps[i] = hp
	}
	return &VectorDB{
		dim:        dim,
		numHashFns: numHashFns,
		lshBuckets: make(map[string][]int),
		lshHPs:     hps,
	}
}

// Insert: 문서 삽입 (insertDocument 대응)
func (db *VectorDB) Insert(doc Document) {
	idx := len(db.docs)
	db.docs = append(db.docs, doc)

	// LSH 버킷에 추가
	key := db.lshKey(doc.Values)
	db.lshBuckets[key] = append(db.lshBuckets[key], idx)
}

// lshKey: LSH 해시 키 계산 (computeLSHKey 대응)
func (db *VectorDB) lshKey(values []float64) string {
	var sb strings.Builder
	for _, hp := range db.lshHPs {
		dot := 0.0
		for i, v := range values {
			dot += v * hp[i]
		}
		if dot >= 0 {
			sb.WriteByte('1')
		} else {
			sb.WriteByte('0')
		}
	}
	return sb.String()
}

// cosSim: 코사인 유사도 계산
func cosSim(a, b []float64) float64 {
	dot, na, nb := 0.0, 0.0, 0.0
	for i := range a {
		dot += a[i] * b[i]
		na += a[i] * a[i]
		nb += b[i] * b[i]
	}
	if na == 0 || nb == 0 {
		return 0
	}
	return dot / (math.Sqrt(na) * math.Sqrt(nb))
}

// l2Dist: L2 거리 계산
func l2Dist(a, b []float64) float64 {
	sum := 0.0
	for i := range a {
		diff := a[i] - b[i]
		sum += diff * diff
	}
	return math.Sqrt(sum)
}

// dotProd: 내적 계산
func dotProd(a, b []float64) float64 {
	sum := 0.0
	for i := range a {
		sum += a[i] * b[i]
	}
	return sum
}

// manhDist: 맨해튼 거리
func manhDist(a, b []float64) float64 {
	sum := 0.0
	for i := range a {
		sum += math.Abs(a[i] - b[i])
	}
	return sum
}

// scoreFunc: 메트릭에 따른 스코어 함수 선택
type scoreFunc func(a, b []float64) float64

func getScoreFunc(metric string) (scoreFunc, bool) {
	switch metric {
	case "cosine":
		return cosSim, true // 높을수록 유사
	case "l2":
		return func(a, b []float64) float64 { return -l2Dist(a, b) }, false // 낮을수록 유사 (음수로 변환)
	case "dot":
		return dotProd, true
	case "manhattan":
		return func(a, b []float64) float64 { return -manhDist(a, b) }, false
	default:
		return cosSim, true
	}
}

// FlatSearch: 완전탐색 검색 (flatIndexSearch 대응)
func (db *VectorDB) FlatSearch(query []float64, k int, metric string, filter *DocMetadata) ([]int, int) {
	scoreFn, _ := getScoreFunc(metric)

	type scored struct {
		idx   int
		score float64
	}
	var results []scored
	scanned := 0

	for i, doc := range db.docs {
		// 메타데이터 필터 (filterDocumentsByMetadata 대응)
		if filter != nil {
			if filter.Category != "" && doc.Metadata.Category != filter.Category {
				continue
			}
			if filter.Lang != "" && doc.Metadata.Lang != filter.Lang {
				continue
			}
		}
		scanned++
		results = append(results, scored{idx: i, score: scoreFn(query, doc.Values)})
	}

	sort.Slice(results, func(i, j int) bool {
		return results[i].score > results[j].score
	})

	topK := make([]int, 0, k)
	for i := 0; i < k && i < len(results); i++ {
		topK = append(topK, results[i].idx)
	}
	return topK, scanned
}

// LSHSearch: LSH 근사 검색 (lshIndexSearch 대응)
func (db *VectorDB) LSHSearch(query []float64, k int, metric string) ([]int, int) {
	key := db.lshKey(query)
	candidates := db.lshBuckets[key]

	scoreFn, _ := getScoreFunc(metric)

	type scored struct {
		idx   int
		score float64
	}
	var results []scored

	for _, idx := range candidates {
		doc := db.docs[idx]
		results = append(results, scored{idx: idx, score: scoreFn(query, doc.Values)})
	}

	sort.Slice(results, func(i, j int) bool {
		return results[i].score > results[j].score
	})

	topK := make([]int, 0, k)
	for i := 0; i < k && i < len(results); i++ {
		topK = append(topK, results[i].idx)
	}
	return topK, len(candidates)
}

// MemoryKB: 메모리 사용량 추정 (KB)
func (db *VectorDB) MemoryKB() int64 {
	// 벡터 데이터: float64(8바이트) * 차원 * 문서 수
	vecMem := int64(len(db.docs)) * int64(db.dim) * 8
	// 해시 함수: float64 * 차원 * 해시 함수 수
	lshMem := int64(db.numHashFns) * int64(db.dim) * 8
	// 버킷 인덱스: 문서 수 * 4바이트 (int32)
	bucketMem := int64(len(db.docs)) * 4
	return (vecMem + lshMem + bucketMem) / 1024
}

