// BenchmarkSearch: 단일 설정 검색 벤치마크 (SearchProfile 생성)
func BenchmarkSearch(
	docCount, dim, k int,
	metric, indexType string,
	metadataFilter bool,
	iterations int,
) SearchProfile {
	rng := rand.New(rand.NewSource(time.Now().UnixNano()))

	// 카테고리, 언어 레이블
	categories := []string{"tech", "science", "art", "business", "health"}
	langs := []string{"en", "ko", "ja", "zh", "de"}

	// DB 구성 (FlatIndex + LSH 동시 보유)
	db := NewVectorDB(dim, 8, 42)

	for i := 0; i < docCount; i++ {
		vals := make([]float64, dim)
		for j := range vals {
			vals[j] = rng.Float64()*2 - 1
		}
		doc := Document{
			ID:     strconv.Itoa(i),
			Values: vals,
			Metadata: DocMetadata{
				Category: categories[rng.Intn(len(categories))],
				Lang:     langs[rng.Intn(len(langs))],
				Score:    rng.Intn(100),
			},
		}
		db.Insert(doc)
	}

	var filter *DocMetadata
	if metadataFilter {
		filter = &DocMetadata{Category: "tech", Lang: "en"}
	}

	var totalMs float64
	var totalScanned, totalReturned int

	for i := 0; i < iterations; i++ {
		query := make([]float64, dim)
		for j := range query {
			query[j] = rng.Float64()*2 - 1
		}

		start := time.Now()
		var results []int
		var scanned int
		if indexType == "flat" {
			results, scanned = db.FlatSearch(query, k, metric, filter)
		} else {
			results, scanned = db.LSHSearch(query, k, metric)
		}
		elapsed := time.Since(start)

		totalMs += float64(elapsed.Microseconds()) / 1000.0
		totalScanned += scanned
		totalReturned += len(results)
	}

	avgMs := totalMs / float64(iterations)
	avgScanned := totalScanned / iterations
	avgReturned := totalReturned / iterations

	// LSH 정확도 계산 (flat 결과와 비교)
	accuracy := 100.0
	if indexType == "lsh" {
		correct := 0
		sample := min(iterations, 20)
		for i := 0; i < sample; i++ {
			query := make([]float64, dim)
			for j := range query {
				query[j] = rng.Float64()*2 - 1
			}
			flatRes, _ := db.FlatSearch(query, k, metric, nil)
			lshRes, _ := db.LSHSearch(query, k, metric)

			flatSet := make(map[int]bool)
			for _, r := range flatRes {
				flatSet[r] = true
			}
			for _, r := range lshRes {
				if flatSet[r] {
					correct++
				}
			}
		}
		if sample*k > 0 {
			accuracy = float64(correct) / float64(sample*k) * 100
		}
	}

	return SearchProfile{
		Metric:            metric,
		IndexType:         indexType,
		TopK:              k,
		DocCount:          docCount,
		Dimension:         dim,
		MetadataFiltered:  metadataFilter,
		QueryTimeMs:       avgMs,
		CandidatesScanned: avgScanned,
		ResultsReturned:   avgReturned,
		Accuracy:          accuracy,
		MemoryKB:          db.MemoryKB(),
	}
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

// CompareIndexes: FlatIndex vs LSHIndex 종합 비교
// collection.fl createCollection + 검색 성능 비교
func CompareIndexes(docCount, dim, k, iterations int) {
	metrics := []string{"cosine", "l2", "dot", "manhattan"}

	fmt.Printf("\n=== FlatIndex vs LSHIndex 비교 (docs=%d, dim=%d, k=%d) ===\n",
		docCount, dim, k)
	fmt.Printf("%-14s %12s %12s %10s %10s\n",
		"메트릭", "Flat(ms)", "LSH(ms)", "LSH정확도", "속도향상")
	fmt.Println(strings.Repeat("-", 62))

	for _, metric := range metrics {
		flatProf := BenchmarkSearch(docCount, dim, k, metric, "flat", false, iterations)
		lshProf := BenchmarkSearch(docCount, dim, k, metric, "lsh", false, iterations)

		speedup := 1.0
		if lshProf.QueryTimeMs > 0 {
			speedup = flatProf.QueryTimeMs / lshProf.QueryTimeMs
		}

		fmt.Printf("%-14s %12.3f %12.3f %9.1f%% %9.2fx\n",
			metric,
			flatProf.QueryTimeMs,
			lshProf.QueryTimeMs,
			lshProf.Accuracy,
			speedup,
		)
	}

	// 메타데이터 필터 영향
	fmt.Printf("\n=== 메타데이터 필터 영향 (cosine, docs=%d) ===\n", docCount)
	noFilter := BenchmarkSearch(docCount, dim, k, "cosine", "flat", false, iterations)
	withFilter := BenchmarkSearch(docCount, dim, k, "cosine", "flat", true, iterations)
	overhead := 0.0
	if noFilter.QueryTimeMs > 0 {
		overhead = (withFilter.QueryTimeMs/noFilter.QueryTimeMs - 1) * 100
	}
	fmt.Printf("  필터 없음:  %.3fms (스캔: %d)\n", noFilter.QueryTimeMs, noFilter.CandidatesScanned)
	fmt.Printf("  필터 적용:  %.3fms (스캔: %d)\n", withFilter.QueryTimeMs, withFilter.CandidatesScanned)
	fmt.Printf("  오버헤드:   %.1f%% (필터로 후보 %d개 감소)\n",
		overhead,
		noFilter.CandidatesScanned-withFilter.CandidatesScanned,
	)
}

// SearchScalability: 문서 수에 따른 성능 곡선
// collection.fl listCollections + 각 크기 비교
func SearchScalability(dim, k int) []ScalabilityPoint {
	docCounts := []int{100, 500, 1000, 5000, 10000}
	iterations := 20

	fmt.Printf("\n=== 검색 확장성 분석 (dim=%d, k=%d) ===\n", dim, k)
	fmt.Printf("%-12s %15s %15s %12s %12s\n",
		"문서 수", "Flat(ms)", "LSH(ms)", "Flat배수", "LSH배수")
	fmt.Println(strings.Repeat("-", 68))

	var points []ScalabilityPoint
	var baseFlatMs, baseLSHMs float64

	for i, docCount := range docCounts {
		flatProf := BenchmarkSearch(docCount, dim, k, "cosine", "flat", false, iterations)
		lshProf := BenchmarkSearch(docCount, dim, k, "cosine", "lsh", false, iterations)

		if i == 0 {
			baseFlatMs = flatProf.QueryTimeMs
			baseLSHMs = lshProf.QueryTimeMs
		}

		flatScale := flatProf.QueryTimeMs / baseFlatMs
		lshScale := 1.0
		if baseLSHMs > 0 {
			lshScale = lshProf.QueryTimeMs / baseLSHMs
		}

		fmt.Printf("%-12d %15.3f %15.3f %12.2fx %12.2fx\n",
			docCount,
			flatProf.QueryTimeMs,
			lshProf.QueryTimeMs,
			flatScale,
			lshScale,
		)

		points = append(points, ScalabilityPoint{
			DocCount:     docCount,
			FlatSearchMs: flatProf.QueryTimeMs,
			LSHSearchMs:  lshProf.QueryTimeMs,
			ScaleFactor:  flatScale,
		})
	}

	// 확장성 등급 판정
	if len(points) >= 2 {
		first := points[0]
		last := points[len(points)-1]
		docRatio := float64(last.DocCount) / float64(first.DocCount)
		timeRatio := last.FlatSearchMs / first.FlatSearchMs
		complexity := "O(N)"
		if timeRatio < docRatio*0.5 {
			complexity = "O(log N)"
		} else if timeRatio > docRatio*1.5 {
			complexity = "O(N²)"
		}
		fmt.Printf("\n  FlatIndex 복잡도 추정: %s (문서 %dx 증가, 시간 %.1fx 증가)\n",
			complexity, int(docRatio), timeRatio)
	}

	return points
}

