// EmbeddingProfile: TF-IDF 임베딩 성능 프로파일
type EmbeddingProfile struct {
	TextLength   int     `json:"text_length"`
	VocabSize    int     `json:"vocab_size"`
	Dimension    int     `json:"dimension"`
	EmbedTimeUs  float64 `json:"embed_time_us"`
	TokenCount   int     `json:"token_count"`
}

// BenchmarkEmbedding: 임베딩 성능 측정
func BenchmarkEmbedding(dim, iterations int) []EmbeddingProfile {
	// 샘플 텍스트 (embedding.fl tokenizeSimple 대응)
	sampleTexts := []string{
		"short text",
		"machine learning vector database embedding similarity search",
		strings.Repeat("vector database performance benchmark test ", 10),
		strings.Repeat("natural language processing deep learning transformer attention mechanism ", 20),
	}

	fmt.Printf("\n=== TF-IDF 임베딩 성능 분석 (dim=%d) ===\n", dim)
	fmt.Printf("%-15s %12s %12s %12s\n", "텍스트길이", "토큰수", "임베딩(μs)", "처리량(doc/s)")
	fmt.Println(strings.Repeat("-", 55))

	var profiles []EmbeddingProfile

	for _, text := range sampleTexts {
		words := strings.Fields(text)
		tokenCount := len(words)

		// TF-IDF 임베딩 시뮬레이션 (embedding.fl embedText 대응)
		start := time.Now()
		for i := 0; i < iterations; i++ {
			_ = simulateEmbed(text, dim)
		}
		elapsed := time.Since(start)

		avgUs := float64(elapsed.Nanoseconds()) / float64(iterations) / 1000.0
		throughput := 1e6 / avgUs

		fmt.Printf("%-15d %12d %12.1f %12.0f\n",
			len(text), tokenCount, avgUs, throughput)

		profiles = append(profiles, EmbeddingProfile{
			TextLength:  len(text),
			VocabSize:   dim,
			Dimension:   dim,
			EmbedTimeUs: avgUs,
			TokenCount:  tokenCount,
		})
	}

	return profiles
}

// simulateEmbed: embedding.fl embedText 로직 시뮬레이션
func simulateEmbed(text string, dim int) []float64 {
	words := strings.Fields(strings.ToLower(text))
	values := make([]float64, dim)

	// TF 계산
	tfMap := make(map[string]float64)
	for _, w := range words {
		if len(w) >= 2 {
			tfMap[w]++
		}
	}
	total := float64(len(words))
	if total == 0 {
		return values
	}

	// 해시 기반 벡터화 (simpleHashWordToIndex 대응)
	for word, count := range tfMap {
		tf := count / total
		// 단순 IDF 근사 (ln(total/count + 1))
		idf := math.Log(total/count + 1)
		tfidf := tf * idf

		// 해시 인덱스 (simpleHashWordToIndex 대응)
		idx := simpleHashToIndex(word, dim)
		values[idx] += tfidf
	}

	// 정규화 (normalizeVector 대응)
	norm := 0.0
	for _, v := range values {
		norm += v * v
	}
	norm = math.Sqrt(norm)
	if norm > 0 {
		for i := range values {
			values[i] /= norm
		}
	}

	return values
}

// simpleHashToIndex: embedding.fl simpleHashWordToIndex 대응
func simpleHashToIndex(word string, dim int) int {
	sum := len(word)
	if len(word) > 0 {
		sum += int(word[0])
	}
	if len(word) > 1 {
		sum += int(word[len(word)-1])
	}
	return sum % dim
}

