// PrintSearchLatencyHistogram: 검색 레이턴시 히스토그램 출력
func PrintSearchLatencyHistogram(profiles []SearchProfile) {
	fmt.Println("\n=== 검색 레이턴시 히스토그램 ===")
	fmt.Println("(각 * = 0.1ms 단위)")

	// 0.1ms 단위 버킷
	buckets := make(map[int]int)
	for _, p := range profiles {
		bucket := int(p.QueryTimeMs / 0.1)
		buckets[bucket]++
	}

	var keys []int
	for k := range buckets {
		keys = append(keys, k)
	}
	sort.Ints(keys)

	maxCount := 0
	for _, count := range buckets {
		if count > maxCount {
			maxCount = count
		}
	}

	for _, k := range keys {
		count := buckets[k]
		bar := strings.Repeat("*", count*50/maxCount+1)
		lowerMs := float64(k) * 0.1
		upperMs := float64(k+1) * 0.1
		fmt.Printf("  [%5.1f~%5.1fms] %s (%d)\n", lowerMs, upperMs, bar, count)
	}
}

// WriteLSTHistogram: 파일로 히스토그램 저장
func WriteLatencyHistogram(profiles []SearchProfile, filename string) error {
	var sb strings.Builder

	sb.WriteString("search_latency_histogram\n")
	sb.WriteString(fmt.Sprintf("generated_at: %s\n", time.Now().Format(time.RFC3339)))
	sb.WriteString(fmt.Sprintf("total_profiles: %d\n\n", len(profiles)))

	buckets := make(map[int][]SearchProfile)
	for _, p := range profiles {
		bucket := int(p.QueryTimeMs / 0.5) // 0.5ms 단위
		buckets[bucket] = append(buckets[bucket], p)
	}

	var keys []int
	for k := range buckets {
		keys = append(keys, k)
	}
	sort.Ints(keys)

	maxCount := 0
	for _, ps := range buckets {
		if len(ps) > maxCount {
			maxCount = len(ps)
		}
	}

	sb.WriteString("latency_ms  count  bar\n")
	sb.WriteString(strings.Repeat("-", 60) + "\n")

	for _, k := range keys {
		ps := buckets[k]
		count := len(ps)
		bar := strings.Repeat("|", count*40/maxCount+1)
		lowerMs := float64(k) * 0.5
		sb.WriteString(fmt.Sprintf("  %6.1f    %5d  %s\n", lowerMs, count, bar))
	}

	// 분위수 계산
	var latencies []float64
	for _, p := range profiles {
		latencies = append(latencies, p.QueryTimeMs)
	}
	sort.Float64s(latencies)
	n := len(latencies)
	if n > 0 {
		sb.WriteString(fmt.Sprintf("\np50: %.3fms\n", latencies[n*50/100]))
		sb.WriteString(fmt.Sprintf("p95: %.3fms\n", latencies[n*95/100]))
		if n > 1 {
			sb.WriteString(fmt.Sprintf("p99: %.3fms\n", latencies[min(n*99/100, n-1)]))
		}
		sb.WriteString(fmt.Sprintf("min: %.3fms\n", latencies[0]))
		sb.WriteString(fmt.Sprintf("max: %.3fms\n", latencies[n-1]))
	}

	if err := os.WriteFile(filename, []byte(sb.String()), 0644); err != nil {
		return fmt.Errorf("히스토그램 저장 실패: %w", err)
	}
	fmt.Printf("[히스토그램] %s 저장 완료\n", filename)
	return nil
}

