func main() {
	// 플래그
	docCount := flag.Int("docs", 1000, "벡터 DB 문서 수")
	dim := flag.Int("dim", 128, "벡터 차원")
	k := flag.Int("k", 10, "Top-K 검색 수")
	iterations := flag.Int("iter", 50, "반복 횟수")
	jsonOut := flag.String("json", "search_profile.json", "JSON 출력 파일")
	histOut := flag.String("hist", "search_latency_histogram.txt", "히스토그램 출력 파일")
	runScalability := flag.Bool("scale", true, "확장성 분석 실행")
	runTopK := flag.Bool("topk", true, "Top-K 분석 실행")
	runEmbed := flag.Bool("embed", true, "임베딩 성능 분석 실행")
	flag.Parse()

	fmt.Println("============================================================")
	fmt.Println("  FreeLang 벡터 DB 검색 성능 프로파일러")
	fmt.Println("============================================================")
	fmt.Printf("  플랫폼: %s/%s\n", runtime.GOOS, runtime.GOARCH)
	fmt.Printf("  문서 수: %d, 차원: %d, Top-K: %d\n", *docCount, *dim, *k)
	fmt.Println()

	var allProfiles []SearchProfile
	metrics := []string{"cosine", "l2", "dot", "manhattan"}

	// 1. 기본 검색 벤치마크 (각 메트릭 × Flat/LSH)
	fmt.Println("--- 1. 기본 검색 성능 벤치마크 ---")
	fmt.Printf("%-14s %-8s %10s %12s %10s\n",
		"메트릭", "인덱스", "시간(ms)", "스캔(avg)", "정확도")
	fmt.Println(strings.Repeat("-", 58))

	for _, metric := range metrics {
		for _, idxType := range []string{"flat", "lsh"} {
			p := BenchmarkSearch(*docCount, *dim, *k, metric, idxType, false, *iterations)
			allProfiles = append(allProfiles, p)
			fmt.Printf("%-14s %-8s %10.3f %12d %9.1f%%\n",
				metric, idxType, p.QueryTimeMs, p.CandidatesScanned, p.Accuracy)
		}
	}

	// 2. FlatIndex vs LSH 비교
	fmt.Println("\n--- 2. FlatIndex vs LSHIndex 비교 ---")
	CompareIndexes(*docCount, *dim, *k, *iterations)

	// 3. 확장성 분석
	var scalPoints []ScalabilityPoint
	if *runScalability {
		fmt.Println("\n--- 3. 검색 확장성 분석 ---")
		scalPoints = SearchScalability(*dim, *k)
	}

	// 4. Top-K 영향 분석
	if *runTopK {
		fmt.Println("\n--- 4. Top-K 영향 분석 ---")
		BenchmarkTopK(*docCount, *dim, *iterations)
	}

	// 5. 임베딩 성능 분석
	if *runEmbed {
		fmt.Println("\n--- 5. TF-IDF 임베딩 성능 ---")
		BenchmarkEmbedding(*dim, *iterations)
	}

	// 6. 히스토그램 출력
	PrintSearchLatencyHistogram(allProfiles)

	// 7. 결과 요약 계산
	var flatSum, lshSum, flatN, lshN float64
	var bestMs, worstMs float64 = math.MaxFloat64, 0
	var bestMetric, worstMetric string

	for _, p := range allProfiles {
		if p.IndexType == "flat" {
			flatSum += p.QueryTimeMs
			flatN++
		} else {
			lshSum += p.QueryTimeMs
			lshN++
		}
		if p.QueryTimeMs < bestMs {
			bestMs = p.QueryTimeMs
			bestMetric = p.Metric + "/" + p.IndexType
		}
		if p.QueryTimeMs > worstMs {
			worstMs = p.QueryTimeMs
			worstMetric = p.Metric + "/" + p.IndexType
		}
	}

	avgFlat := flatSum / flatN
	avgLSH := lshSum / lshN
	if lshN == 0 {
		avgLSH = 0
	}

	summary := BenchmarkSummary{
		FastestMetric:   bestMetric,
		FastestMetricMs: bestMs,
		SlowestMetric:   worstMetric,
		SlowestMetricMs: worstMs,
		AvgFlatSearchMs: avgFlat,
		AvgLSHSearchMs:  avgLSH,
		MaxThroughputOps: 1.0 / (bestMs / 1000),
	}

	// 8. JSON 저장
	config := BenchmarkConfig{
		DocCounts:  []int{*docCount},
		Dimensions: []int{*dim},
		TopK:       []int{*k},
		Metrics:    metrics,
		Iterations: *iterations,
	}

	result := BenchmarkResult{
		Config:      config,
		Profiles:    allProfiles,
		Summary:     summary,
		GeneratedAt: time.Now().Format(time.RFC3339),
		Platform:    runtime.GOOS + "/" + runtime.GOARCH,
	}

	if err := ExportBenchmarkJSON(result, *jsonOut); err != nil {
		fmt.Fprintf(os.Stderr, "JSON 저장 실패: %v\n", err)
	}

	// 9. 히스토그램 파일 저장
	if err := WriteLatencyHistogram(allProfiles, *histOut); err != nil {
		fmt.Fprintf(os.Stderr, "히스토그램 저장 실패: %v\n", err)
	}

	// 10. 요약 출력
	fmt.Println("\n============================================================")
	fmt.Println("  검색 성능 프로파일링 완료")
	fmt.Println("============================================================")
	fmt.Printf("  가장 빠른 설정: %s (%.3fms)\n", summary.FastestMetric, summary.FastestMetricMs)
	fmt.Printf("  가장 느린 설정: %s (%.3fms)\n", summary.SlowestMetric, summary.SlowestMetricMs)
	fmt.Printf("  Flat 평균:      %.3fms\n", summary.AvgFlatSearchMs)
	fmt.Printf("  LSH 평균:       %.3fms\n", summary.AvgLSHSearchMs)
	fmt.Printf("  최대 처리량:    %.0f ops/sec\n", summary.MaxThroughputOps)
	if len(scalPoints) > 0 {
		last := scalPoints[len(scalPoints)-1]
		fmt.Printf("  %d문서 Flat검색: %.3fms\n", last.DocCount, last.FlatSearchMs)
	}
	fmt.Printf("\n  - JSON: %s\n", *jsonOut)
	fmt.Printf("  - 히스토그램: %s\n", *histOut)
	fmt.Println("============================================================")
}
